import fs from 'node:fs';
import path from 'node:path';
import { globSync } from 'glob';
import { config } from '../../vendor/nerve/config.js';

function stamp() {
  const d = new Date();
  const p = (n) => String(n).padStart(2, '0');
  return `${d.getUTCFullYear()}${p(d.getUTCMonth() + 1)}${p(d.getUTCDate())}T${p(d.getUTCHours())}${p(d.getUTCMinutes())}${p(d.getUTCSeconds())}Z`;
}

export function snapshotAllSessions() {
  const files = globSync(path.join(config.agentsRoot, '*/sessions/*.jsonl')).sort();
  const runId = stamp();
  const root = path.join(config.archiveRoot, runId);
  fs.mkdirSync(root, { recursive: true });

  let copied = 0;
  for (const src of files) {
    const rel = path.relative(config.agentsRoot, src);
    const dest = path.join(root, rel);
    fs.mkdirSync(path.dirname(dest), { recursive: true });
    fs.copyFileSync(src, dest);
    copied += 1;
  }

  return { runId, archivePath: root, filesCopied: copied };
}

export function restoreArchiveFile(archiveFile) {
  if (!archiveFile || !fs.existsSync(archiveFile)) throw new Error('archive file not found');
  const rel = path.relative(config.archiveRoot, archiveFile);
  const parts = rel.split(path.sep);
  if (parts.length < 3) throw new Error('invalid archive file layout');
  const targetRel = parts.slice(1).join(path.sep); // strip runId
  const dest = path.join(config.agentsRoot, targetRel);
  fs.mkdirSync(path.dirname(dest), { recursive: true });
  fs.copyFileSync(archiveFile, dest);
  return { archiveFile, restoredTo: dest };
}

import fs from 'node:fs';
import path from 'node:path';
import { globSync } from 'glob';
import { db, nowIso } from './db.js';
import { extractText, parseLine } from './parser.js';
import { config } from '../../vendor/nerve/config.js';

function parseAgentAndSession(file) {
  const parts = file.split(path.sep);
  const i = parts.lastIndexOf('agents');
  const agent = i >= 0 ? parts[i + 1] : 'unknown';
  return { agent };
}

function hashTitle(firstMessageText, sessionId) {
  return (firstMessageText || sessionId || 'session').slice(0, 100);
}

function discoverTranscriptFiles() {
  return globSync(path.join(config.agentsRoot, '*/sessions/*.jsonl')).sort();
}

function discoverArchiveFiles() {
  if (!config.archiveRoot || !fs.existsSync(config.archiveRoot)) return [];
  return globSync(path.join(config.archiveRoot, '**/*.jsonl')).sort();
}

function discoverMemoryFiles() {
  if (!config.memoryRoot || !fs.existsSync(config.memoryRoot)) return [];
  return globSync(path.join(config.memoryRoot, '*.md')).sort();
}

function discoverLogFiles() {
  if (!config.logsRoot || !fs.existsSync(config.logsRoot)) return [];
  return globSync(path.join(config.logsRoot, '**/*.jsonl')).sort();
}

function upsertSessionBundle({ sessionId, agent, sessionFile, sessionStartedAt, sessionEndedAt, parentSessionFile = null, title, cwd = null, messages, toolCalls, edges, metadata }) {
  const tx = db.transaction(() => {
    db.prepare('DELETE FROM messages_fts WHERE session_id = ?').run(sessionId);
    db.prepare('DELETE FROM tool_calls WHERE session_id = ?').run(sessionId);
    db.prepare('DELETE FROM messages WHERE session_id = ?').run(sessionId);
    db.prepare('DELETE FROM edges WHERE session_id = ?').run(sessionId);

    db.prepare(`INSERT INTO sessions (
      id, agent_name, session_file, session_started_at, session_ended_at, parent_session_file,
      title, cwd, message_count, tool_call_count, last_message_at, metadata_json, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(id) DO UPDATE SET
      agent_name=excluded.agent_name,
      session_file=excluded.session_file,
      session_started_at=excluded.session_started_at,
      session_ended_at=excluded.session_ended_at,
      parent_session_file=excluded.parent_session_file,
      title=excluded.title,
      cwd=excluded.cwd,
      message_count=excluded.message_count,
      tool_call_count=excluded.tool_call_count,
      last_message_at=excluded.last_message_at,
      metadata_json=excluded.metadata_json,
      updated_at=excluded.updated_at`).run(
      sessionId,
      agent,
      sessionFile,
      sessionStartedAt || null,
      sessionEndedAt || null,
      parentSessionFile || null,
      title || sessionId,
      cwd || null,
      messages.length,
      toolCalls.length,
      messages[messages.length - 1]?.ts || sessionEndedAt || sessionStartedAt || null,
      JSON.stringify(metadata || {}),
      nowIso(),
    );

    const insMsg = db.prepare(`INSERT INTO messages
      (message_id, session_id, parent_message_id, ts, role, type, content_text, content_json, raw_json)
      VALUES (@message_id, ?, @parent_message_id, @ts, @role, @type, @content_text, @content_json, @raw_json)`);
    const insFts = db.prepare('INSERT INTO messages_fts (session_id, message_id, role, content_text) VALUES (?, ?, ?, ?)');
    for (const m of messages) {
      insMsg.run(sessionId, m);
      insFts.run(sessionId, m.message_id, m.role, m.content_text || '');
    }

    const insTool = db.prepare(`INSERT INTO tool_calls
      (session_id, message_id, tool_call_id, tool_name, arguments_json, result_json, ts, raw_json)
      VALUES (@session_id,@message_id,@tool_call_id,@tool_name,@arguments_json,@result_json,@ts,@raw_json)`);
    for (const t of toolCalls) insTool.run({ session_id: sessionId, ...t });

    const insEdge = db.prepare('INSERT INTO edges (session_id, edge_type, parent_id, child_id, metadata_json) VALUES (?, ?, ?, ?, ?)');
    for (const e of edges) insEdge.run(sessionId, e.edge_type, e.parent_id, e.child_id, e.metadata_json);
  });

  tx();
}

function parseMemoryFrontmatter(text) {
  if (!text.startsWith('---\n')) return {};
  const end = text.indexOf('\n---', 4);
  if (end === -1) return {};
  const block = text.slice(4, end).trim();
  const out = {};
  for (const line of block.split('\n')) {
    const idx = line.indexOf(':');
    if (idx <= 0) continue;
    const k = line.slice(0, idx).trim();
    const v = line.slice(idx + 1).trim();
    if (k && v) out[k] = v.replace(/^['"]|['"]$/g, '');
  }
  return out;
}

function parseSessionJsonl(file) {
  const text = fs.readFileSync(file, 'utf8');
  const lines = text.split('\n').filter(Boolean);
  let session = null;
  let titleOverride = '';
  const messages = [];
  const toolCalls = [];
  const edges = [];
  let firstText = '';

  for (const line of lines) {
    const obj = parseLine(line);
    if (!obj) continue;

    if (obj.type === 'session') {
      session = obj;
      continue;
    }

    if (obj.type === 'session_title') {
      titleOverride = String(obj.title || '').trim();
      continue;
    }

    const msgId = obj.id || null;
    const parentId = obj.parentId || null;
    if (parentId && msgId) {
      edges.push({ edge_type: 'message_parent', parent_id: parentId, child_id: msgId, metadata_json: null });
    }

    if (obj.type === 'message') {
      const role = obj.message?.role || null;
      const msgContent = obj.message?.content ?? obj.message ?? obj;
      const contentText = extractText(msgContent);
      if (!firstText && contentText) firstText = contentText;
      messages.push({
        message_id: msgId,
        parent_message_id: parentId,
        ts: obj.timestamp || null,
        role,
        type: obj.type,
        content_text: contentText,
        content_json: JSON.stringify(msgContent ?? null),
        raw_json: JSON.stringify(obj),
      });

      const contentArr = Array.isArray(obj.message?.content) ? obj.message.content : [];
      for (const c of contentArr) {
        if (c?.type === 'toolCall') {
          toolCalls.push({
            message_id: msgId,
            tool_call_id: c.id || null,
